import Foundation

/// Domain entity representing a crisis prediction generated by the ML model.
struct Prediction: Identifiable, Codable, Equatable, Sendable {
    let id: String
    let locationID: String
    let locationName: String
    let crisisProbability: Double
    let confidence: Double
    let riskScore: Int
    let riskLevel: RiskLevel
    let contributingFactors: [ContributingFactor]
    let timestamp: Date
    let validUntil: Date

    /// Whether the prediction is still within its validity window.
    var isValid: Bool {
        Date() < validUntil
    }

    var riskPercentageString: String {
        "\(riskScore)%"
    }

    var confidencePercentageString: String {
        String(format: "%.0f%%", confidence * 100)
    }
}

/// A factor contributing to the crisis risk assessment.
struct ContributingFactor: Identifiable, Codable, Equatable, Sendable {
    var id: String { name }
    let name: String
    let description: String
    let severity: FactorSeverity
    let value: Double
    let unit: String

    var formattedValue: String {
        String(format: "%.1f %@", value, unit)
    }
}

/// Severity levels for contributing factors.
enum FactorSeverity: String, Codable, CaseIterable, Sendable {
    case low
    case moderate
    case high
    case critical
}

